commands.examples:
SELECT CONCAT(first_name, ' ', last_name) AS full_name FROM users;
SELECT CONCAT_WS(', ', city, state, country) AS address FROM users;
SELECT CONCAT('Hello, ', username, '!') FROM users;

SELECT SUBSTRING('Hello World', 1, 5);  -- 'Hello'
SELECT SUBSTRING(email, 1, LOCATE('@', email)-1) AS username FROM users;
SELECT LEFT(title, 50) AS short_title FROM articles;
SELECT RIGHT(phone, 4) AS last_four FROM users;

SELECT REPLACE('Hello World', 'World', 'MySQL');
UPDATE articles SET body = REPLACE(body, 'http://', 'https://');
SELECT REPLACE(phone, '-', '') AS clean_phone FROM users;

SELECT TRIM('  hello  ');  -- 'hello'
SELECT TRIM(LEADING '0' FROM '00123');  -- '123'
SELECT LTRIM('  hello');
SELECT RTRIM('hello  ');

SELECT UPPER(username) FROM users;
SELECT LOWER(email) FROM users;
SELECT * FROM users WHERE LOWER(email) = 'john@mail.com';

SELECT * FROM users WHERE email REGEXP '^[a-z]+@gmail\\.com$';
SELECT * FROM products WHERE name REGEXP 'laptop|notebook';
SELECT REGEXP_REPLACE(phone, '[^0-9]', '') AS clean_phone FROM users;

SELECT FORMAT(1234567.891, 2);  -- '1,234,567.89'
SELECT LPAD(id, 6, '0') AS order_no FROM orders;  -- '000042'
SELECT RPAD(name, 20, '.') FROM products;
